import React from 'react';
import { Package, Clock, ShoppingBag, CheckCircle, Ship, MapPin } from 'lucide-react';
import '../../assets/styles/OrderTracker.css';

const milestones = [
  { 
    id: 'Order Placed', 
    label: 'Order Placed', 
    shortLabel: 'Placed',
    desc: 'Your request for heritage goodness has been received successfully.',
    icon: ShoppingBag 
  },
  { 
    id: 'In Transit', 
    label: 'In Transit', 
    shortLabel: 'Transit',
    desc: 'Our logistics partners are carefully moving your artisanal order.',
    icon: Ship 
  },
  { 
    id: 'Out for Delivery', 
    label: 'Out for Delivery', 
    shortLabel: 'Delivery',
    desc: 'Your delivery partner is on their way to your specified location.',
    icon: MapPin 
  },
  { 
    id: 'Delivered', 
    label: 'Delivered', 
    shortLabel: 'Delivered',
    desc: 'Order received! Enjoy the authentic taste of heritage harvest.',
    icon: CheckCircle 
  },
];

const OrderTracker = ({ status }) => {
  const currentStepIndex = milestones.findIndex(m => m.id === status);

  return (
    <div className="vertical-tracker-wrapper">
      <div className="tracker-timeline">
        {/* The Vertical Progress Line */}
        <div className="tracker-timeline-line">
          <div 
            className="tracker-timeline-progress" 
            style={{ height: `${(currentStepIndex / (milestones.length - 1)) * 100}%` }}
          />
        </div>

        {milestones.map((milestone, index) => {
          const Icon = milestone.icon;
          const isCompleted = index < currentStepIndex;
          const isCurrent = index === currentStepIndex;
          const isActive = index <= currentStepIndex;

          return (
            <div 
              key={milestone.id} 
              className={`tracker-timeline-item ${index % 2 === 0 ? 'left' : 'right'} ${isActive ? 'active' : ''} ${isCurrent ? 'current' : ''}`}
            >
              <div className="tracker-card">
                <div className="card-header-row">
                  <span className="card-stage-tag">{milestone.shortLabel}</span>
                  <Icon size={18} className="stage-icon" />
                </div>
                <h3>{milestone.label}</h3>
                <p>{milestone.desc}</p>
                {isCompleted && <div className="completed-badge"><CheckCircle size={12} /> Passed</div>}
              </div>

              <div className={`timeline-dot-wrapper ${isActive ? 'active' : ''}`}>
                <div className="timeline-dot-outer">
                   <div className="timeline-dot-inner"></div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default OrderTracker;
